<script lang="ts" module>
	export type MessageStyle = "info" | "warning" | "danger" | "success";
</script>

<script lang="ts">
	import Button from "./Button.svelte";
	import Icon from "./Icon.svelte";
	import { type IconName } from "../icons/names";
	import { copyToClipboard } from "../utils/clipboard";
	import { type ComponentColorType } from "../utils/colorTypes";
	import type { Snippet } from "svelte";

	interface Props {
		icon?: IconName;
		style?: MessageStyle;
		outlined?: boolean;
		filled?: boolean;
		class?: string;
		primaryLabel?: string;
		primaryIcon?: IconName;
		primaryTestId?: string;
		primaryAction?: () => void;
		secondaryLabel?: string;
		secondaryIcon?: IconName;
		secondaryTestId?: string;
		secondaryAction?: () => void;
		tertiaryLabel?: string;
		tertiaryTestId?: string;
		tertiaryIcon?: IconName;
		tertiaryAction?: () => void;
		shadow?: boolean;
		error?: string | undefined;
		title?: Snippet;
		content?: Snippet;
		testId?: string;
	}

	const {
		icon: iconName,
		style = "info",
		outlined = true,
		filled = false,
		class: className = "",
		primaryLabel = "",
		primaryIcon,
		primaryTestId,
		primaryAction,
		secondaryLabel = "",
		secondaryIcon,
		secondaryTestId,
		secondaryAction,
		tertiaryLabel = "",
		tertiaryIcon,
		tertiaryTestId,
		tertiaryAction,
		shadow = false,
		error,
		title,
		content,
		testId,
	}: Props = $props();

	const iconMap: { [Key in MessageStyle]: IconName } = {
		info: "info",
		warning: "warning",
		danger: "danger",
		success: "tick-circle",
	};

	const iconColorMap: { [Key in MessageStyle]: string } = {
		info: "var(--fill-pop-bg)",
		warning: "var(--fill-warn-bg)",
		danger: "var(--fill-danger-bg)",
		success: "var(--fill-safe-bg)",
	};

	const primaryButtonMap: { [Key in MessageStyle]: ComponentColorType } = {
		info: "pop",
		warning: "warning",
		danger: "danger",
		success: "pop",
	};

	const resolvedIconName = $derived(iconName ?? (iconMap[style] as IconName));
</script>

<div
	data-testid={testId}
	class="info-message {style} {className}"
	class:has-border={outlined}
	class:has-background={filled}
	class:shadow
>
	<div class="info-message__icon">
		<Icon name={resolvedIconName} color={iconColorMap[style]} />
	</div>
	<div class="info-message__inner">
		<div class="info-message__content">
			{#if title}
				<div class="info-message__title text-13 text-body text-bold">
					{@render title()}
				</div>
			{/if}

			{#if content}
				<div class="info-message__text text-12 text-body">
					{@render content()}
				</div>
			{/if}
		</div>

		{#if error}
			<code
				class="info-message__code-block scrollbar"
				class:warn={style === "warning"}
				class:error={style === "danger"}
			>
				{error}
			</code>
		{/if}

		{#if primaryLabel || secondaryLabel}
			<div class="info-message__actions">
				{#if error}
					<Button kind="ghost" onclick={() => copyToClipboard(error)} icon="copy">
						Copy error message
					</Button>
				{/if}
				{#if tertiaryLabel}
					<Button
						kind="outline"
						testId={tertiaryTestId}
						onclick={() => tertiaryAction?.()}
						icon={tertiaryIcon}
					>
						{tertiaryLabel}
					</Button>
				{/if}
				{#if secondaryLabel}
					<Button
						kind="outline"
						testId={secondaryTestId}
						onclick={() => secondaryAction?.()}
						icon={secondaryIcon}
					>
						{secondaryLabel}
					</Button>
				{/if}
				{#if primaryLabel}
					<Button
						style={primaryButtonMap[style]}
						onclick={() => primaryAction?.()}
						icon={primaryIcon}
						testId={primaryTestId}
					>
						{primaryLabel}
					</Button>
				{/if}
			</div>
		{/if}
	</div>
</div>

