n srgb,var(--fill-danger-bg) 20%,transparent)}:global(.info-message__text a){cursor:pointer;text-decoration:underline;word-break:break-all}:global(.info-message__text p:not(:last-child)){margin-bottom:.625rem}:global(.info-message__text ul){list-style-type:circle;padding:0 0 0 1rem}</style>
